mapper.select:
SELECT POST_ID, BOARD_ID, MBR_ID, TITLE, CONTENT, VIEW_COUNT, RCMD_CNT, NOTICE_YN, PIN_YN, PUB_YN, R_DTTM, R_USER, REG_IP, U_DTTM, U_USER, UPD_IP, DEL_YN, USE_YN FROM TB_POST WHERE DEL_YN = 'N' AND BOARD_ID = #{boardId}
AND TITLE LIKE '%${titleKeyword}%'
ORDER BY NOTICE_YN DESC, R_DTTM DESC
